import Foundation

/// Провайдер ответа
protocol BluetoothCommandResponseProvider {

    associatedtype Response

    /// Обертка ответа команды
    var response: BluetoothCommandResponseBuilder<Response> { get }
}

/// обертка сериализатора данных
struct BluetoothCommandResponseBuilder<T> {

    public typealias Decoding = (BluetoothRawStorage) throws -> T

    private var decode: Decoding

    public init(decoding: @escaping Decoding) {
        decode = decoding
    }

    /// Преобразование сырых данных, в необходимый ответ команды
    public func decode(_ data: BluetoothRawStorage) throws -> T {
        try decode(data)
    }
}

/// Дефолтный ответ команд
struct BluetoothDefaultResponse {

    /// Валидный ли ответ от устройства
    var isValid: Bool = true
}

