import Foundation

protocol BluetoothCommand: BluetoothCommandRequestConfigurator,
                           BluetoothRequestPackage,
                           BluetoothCommandResponseProvider,
                           BluetoothRawStorageProvider {
}

extension BluetoothCommand {

    var request: BluetoothCommandRequestBuilder<BluetoothCommandRequest> {
        .init { result in
            let dataWithSize: [UInt8] = UInt32(result.count).asBytes + result
            /// Максимальный размер отправляемого пакеты команды составляет 18 байт
            return dataWithSize.chunks(by: 18).map { Data($0) }
        }
    }

    var response: BluetoothCommandResponseBuilder<BluetoothDefaultResponse> {
        .init { storage in
            return .init(isValid: storage.isValid)
        }
    }

    var storageType: StorageType {
        .default
    }

    var identifier: String {
        "\(Self.self)"
    }
}

