import Foundation

/// Сырые данные Bluetooth
protocol BluetoothRawStorage {

    /// Длина команды
    var estimatedLength: UInt32 { get }

    /// Команда
    var command: UInt32 { get }

    /// Валидность ответа команды
    var isValid: Bool { get }

    /// Признак последнего пакета
    var isLastPackage: Bool { get }

    /// Длина заголовка
    var headerSize: Int { get }

    /// Заголовок
    var header: [UInt8] { get set }

    /// Данные
    var body: [UInt8] { get }

    /// Добавляет сырые данные от устройства
    func append(bytes: [UInt8])
}

extension BluetoothRawStorage {

    var isLastPackage: Bool {
        let packageCount = Int(estimatedLength) - headerSize - body.count
        return packageCount == 0
    }
}

/// Провайдер сырых данных
protocol BluetoothRawStorageProvider {

    /// Хранилище сырых данных
    var storageType: StorageType { get }
}

/// Тип хранилища
enum StorageType {
    /// Системное
    case system
    /// Дефолтное
    case `default`
    /// Кастомное
    case custom(BluetoothRawStorage)

    /// Инстанс хранилища
    var instance: BluetoothRawStorage {
        switch self {
        case .default:
            return DefaultBluetoothRawStorage()
        case .system:
            return SystemBluetoothRawStorage()
        case .custom(let storage):
            return storage
        }
    }
}

/// Дефолтное хранилище сырых данных
final class DefaultBluetoothRawStorage: BluetoothRawStorage {

    var estimatedLength: UInt32 = 0
    var command: UInt32 = 0
    var isValid: Bool = false
    var headerSize: Int = 0
    var header: [UInt8] = []
    var body: [UInt8] = []

    func append(bytes: [UInt8]) {
        var bytes = bytes

        parse(header: &bytes)
        body.append(contentsOf: bytes)
    }

    private func parse(header bytes: inout [UInt8]) {
        /// Проверка того, что заголовок уже распарсен
        if headerSize > 0 {
            return
        }

        /// Длина команды
        let lengthOffset = 4
        /// Название команды
        let commandOffset = 4
        /// Ключ валидации
        let validOffset = 4

        let readedSize = lengthOffset + commandOffset + validOffset

        let estimatedLenght: UInt32 = bytes.toBinaryInteger(start: 0)
        let command: UInt32 = bytes.toBinaryInteger(start: lengthOffset)
        let valid: UInt32 = bytes.toBinaryInteger(start: lengthOffset + commandOffset)

        var packLenthOffset = 0

        /// Вычисляем длину пакета данных
        if command == BluetoothCommandType.readVirtualString.rawValue {
            let packLenth: UInt32 = bytes.toBinaryInteger(start: readedSize)
            if packLenth == Int(estimatedLenght) - readedSize {
                 /// Длина пакета данных без заголовка
                 packLenthOffset = 4
            }
        }

        self.headerSize = commandOffset + validOffset + packLenthOffset
        self.estimatedLength = estimatedLenght
        self.command = command
        self.isValid = valid == 1
        self.header = Array(bytes.prefix(readedSize + packLenthOffset))

        bytes = Array(bytes.dropFirst(readedSize + packLenthOffset))
    }
}

/// Хранилище сырых данных для системных команд
/// Необходимо использовать в тех командах, где не требуется проверять ключ валидации
final class SystemBluetoothRawStorage: BluetoothRawStorage {

    var estimatedLength: UInt32 = 0
    var command: UInt32 = 0
    var isValid: Bool = false
    var headerSize: Int = 0
    var header: [UInt8] = []
    var body: [UInt8] = []

    func append(bytes: [UInt8]) {
        var bytes = bytes

        parse(header: &bytes)
        body.append(contentsOf: bytes)
    }

    private func parse(header bytes: inout [UInt8]) {
        /// Проверка того, что заголовок уже распарсен
        if headerSize > 0 {
            return
        }

        /// Длина команды
        let lengthOffset = 4
        /// Название команды
        let commandOffset = 4

        /// Вычисление длины команды БЕЗ учета первого слова
        self.estimatedLength = bytes.toBinaryInteger(start: 0)

        self.command = bytes.toBinaryInteger(start: lengthOffset)

        headerSize = commandOffset

        self.header = Array(bytes.prefix(lengthOffset + commandOffset))

        bytes = Array(bytes.dropFirst(lengthOffset + commandOffset))
    }
}

